import{_ as e,o as i,c as l,ag as a}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Funzioni | Dotfiles (IT)","titleTemplate":":title","description":"Funzioni shell che migliorano la tua esperienza con il terminale. Utility per test API, gestione file, operazioni di sistema e altro.","frontmatter":{"title":"Funzioni | Dotfiles","description":"Funzioni shell che migliorano la tua esperienza con il terminale. Utility per test API, gestione file, operazioni di sistema e altro.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Funzioni preview","canonical":"/it/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Funzioni","pageType":"docs","schemaType":"WebPage","metaTitle":"Funzioni - Dotfiles (IT)","permalink":"/it/functions/","meta":[{"name":"keywords","content":"funzioni, shell, bash, zsh, dotfiles, produttivita, utility, api, file, sistema"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Funzioni shell che migliorano la tua esperienza con il terminale. Utility per test API, gestione file, operazioni di sistema e altro."},{"name":"twitter:title","content":"Funzioni - Dotfiles"},{"name":"og:title","content":"Funzioni - Dotfiles"},{"name":"og:description","content":"Funzioni shell che migliorano la tua esperienza con il terminale. Utility per test API, gestione file, operazioni di sistema e altro."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/functions/index.md","filePath":"it/functions/index.md","lastUpdated":1773010926000}'),d={name:"it/functions/index.md"};function o(n,t,s,c,r,f){return i(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="funzioni" tabindex="-1">Funzioni <a class="header-anchor" href="#funzioni" aria-label="Permalink to &quot;Funzioni&quot;">​</a></h1><p>Utility shell per aumentare la tua produttivita su macOS, Linux e Windows.</p><h2 id="scopri" tabindex="-1">Scopri <a class="header-anchor" href="#scopri" aria-label="Permalink to &quot;Scopri&quot;">​</a></h2><p>Le funzioni sono definite come singoli file <code>.sh</code>. Durante <code>chezmoi apply</code>, vengono aggregate in <code>~/.config/shell/functions.sh</code> e caricate dalla tua shell.</p><h2 id="inizia" tabindex="-1">Inizia <a class="header-anchor" href="#inizia" aria-label="Permalink to &quot;Inizia&quot;">​</a></h2><h3 id="aggiungi-una-funzione" tabindex="-1">Aggiungi una funzione <a class="header-anchor" href="#aggiungi-una-funzione" aria-label="Permalink to &quot;Aggiungi una funzione&quot;">​</a></h3><ol><li>Crea un nuovo file <code>.sh</code> (es., <code>myfunc.sh</code>)</li><li>Aggiungi la definizione della tua funzione</li><li>Applica le modifiche:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="riferimento" tabindex="-1">Riferimento <a class="header-anchor" href="#riferimento" aria-label="Permalink to &quot;Riferimento&quot;">​</a></h2><h3 id="test-api" tabindex="-1">Test API <a class="header-anchor" href="#test-api" aria-label="Permalink to &quot;Test API&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">Controlla lo stato di una o piu API</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">Monitora il tempo di risposta API</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">Esegui test di carico base</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">Debug richieste HTTP con timing</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="utility-http" tabindex="-1">Utility HTTP <a class="header-anchor" href="#utility-http" aria-label="Permalink to &quot;Utility HTTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">Visualizza header HTTP</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">Controlla codice stato HTTP</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">Misura metriche timing HTTP</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">Visualizza codice sorgente sito web</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">Trova processo che usa una porta</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="gestione-file" tabindex="-1">Gestione file <a class="header-anchor" href="#gestione-file" aria-label="Permalink to &quot;Gestione file&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">Crea backup con timestamp</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Codifica e decodifica Base64</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">Estrai formati archivio</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">Visualizza file in formato hex</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">Rinomina estensioni in batch</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">Controlla dimensione file o directory</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">Crea archivi ZIP</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="nomi-file" tabindex="-1">Nomi file <a class="header-anchor" href="#nomi-file" aria-label="Permalink to &quot;Nomi file&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">Converti in kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">Converti in minuscolo</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">Converti in sentence case</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">Converti in snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Converti in Title Case</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">Converti in MAIUSCOLO</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="utility-di-sistema" tabindex="-1">Utility di sistema <a class="header-anchor" href="#utility-di-sistema" aria-label="Permalink to &quot;Utility di sistema&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">Impedisci al sistema di andare in sleep</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">Rileva ambiente OS</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">Pulisci spazio disco purgabile</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Attiva/disattiva file nascosti nel Finder</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">Visualizza informazioni host</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">Visualizza statistiche uso comandi</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">Elenca file modificati di recente</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">Logout multipiattaforma</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">Elenca processi utente</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">Cronometro da terminale</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">Visualizza informazioni di sistema</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="comandi-caffeine" tabindex="-1">Comandi Caffeine <a class="header-anchor" href="#comandi-caffeine" aria-label="Permalink to &quot;Comandi Caffeine&quot;">​</a></h3><p>Impedisci al sistema di andare in sleep o attivare lo screensaver.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Comando</th><th style="text-align:left;">Descrizione</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">Avvia il daemon caffeine</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">Controlla se il daemon e in esecuzione</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">Mantieni lo schermo attivo</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">Permetti allo schermo di andare in sleep</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">Attiva/disattiva schermo attivo</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">Arresta il daemon</td></tr></tbody></table><p>Funziona su macOS (<code>caffeinate</code> nativo), Linux (<code>xdg-screensaver</code>) e Windows (PowerShell).</p><h3 id="sicurezza" tabindex="-1">Sicurezza <a class="header-anchor" href="#sicurezza" aria-label="Permalink to &quot;Sicurezza&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">Genera password sicure</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">Genera coppie di chiavi SSH</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="navigazione" tabindex="-1">Navigazione <a class="header-anchor" href="#navigazione" aria-label="Permalink to &quot;Navigazione&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">Cambia directory ed elenca</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">Navigazione rapida directory</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">Monta sola lettura come lettura-scrittura</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">Rimuovi directory</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">Espelli disco in sicurezza</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="varie" tabindex="-1">Varie <a class="header-anchor" href="#varie" aria-label="Permalink to &quot;Varie&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Funzione</th><th style="text-align:left;">Descrizione</th><th style="text-align:left;">Utilizzo</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">Effetti Matrix nel terminale</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">Aggiungi directory al PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">Apri in macOS Quick Look</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">Apri in VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="compatibilita" tabindex="-1">Compatibilita <a class="header-anchor" href="#compatibilita" aria-label="Permalink to &quot;Compatibilita&quot;">​</a></h2><ul><li><strong>macOS</strong> — Supporto completo con utility specifiche macOS</li><li><strong>Linux</strong> — Compatibile con le distribuzioni comuni</li><li><strong>Windows</strong> — Supporto tramite WSL, Cygwin o Git Bash</li></ul><h2 id="aiuto" tabindex="-1">Aiuto <a class="header-anchor" href="#aiuto" aria-label="Permalink to &quot;Aiuto&quot;">​</a></h2><p>Ogni funzione include documentazione tramite <code>--help</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(d,[["render",o]]);export{h as __pageData,y as default};
